{
  "name": "KnowApp",
  "description": "A community-driven marketplace connecting people who need home projects done on a budget with skilled neighbors and handymen. Features AI-powered project estimation and job post drafting."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum JobCategory {
  PLUMBING = 'Plumbing',
  ELECTRICAL = 'Electrical',
  CARPENTRY = 'Carpentry',
  PAINTING = 'Painting',
  CLEANING = 'Cleaning',
  YARD_WORK = 'Yard Work',
  GENERAL_LABOR = 'General Labor',
  OTHER = 'Other'
}

export enum BudgetType {
  FIXED = 'Fixed Price',
  HOURLY = 'Hourly',
  BARTER = 'Barter/Trade',
  VOLUNTEER = 'Volunteer Request'
}

export interface JobPost {
  id: string;
  title: string;
  description: string;
  category: JobCategory;
  budgetType: BudgetType;
  budgetAmount?: number; // Optional for Barter/Volunteer
  barterDescription?: string;
  location: string;
  postedAt: Date;
  authorName: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  isThinking?: boolean;
}

import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are the "KnowApp Project Advisor". Your goal is to help users who might have limited funds to define their home improvement needs.
When a user describes a problem (e.g., "my sink is leaking" or "hole in wall"), you should:
1. Identify the likely job category (e.g., Plumbing, Carpentry).
2. Estimate the difficulty level (Easy DIY vs. Professional needed).
3. Suggest a concise Title and Description for a job posting.
4. Estimate a fair "community budget" (low cost) or suggest specific items for Barter/Trade if they have no money.
5. Be encouraging and helpful.
6. Keep responses structured and concise. 
`;

export const getProjectAdvice = async (userQuery: string): Promise<string> => {
  if (!process.env.API_KEY) {
    console.warn("API Key is missing. Returning mock response.");
    return "I can't connect to my brain right now (Missing API Key), but generally, for home projects, try to describe the issue clearly and take photos!";
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: userQuery,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      }
    });

    return response.text || "I couldn't generate advice at this moment. Please try again.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Sorry, I encountered an error while analyzing your project. Please try again later.";
  }
};

import React from 'react';
import { Home, Hammer, PlusCircle, MessageCircle, Menu, X } from 'lucide-react';

interface NavigationProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

export const Navigation: React.FC<NavigationProps> = ({ activeTab, setActiveTab }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = React.useState(false);

  const navItems = [
    { id: 'home', label: 'Home', icon: Home },
    { id: 'jobs', label: 'Find Work', icon: Hammer },
    { id: 'post', label: 'Post a Job', icon: PlusCircle },
    { id: 'advisor', label: 'AI Advisor', icon: MessageCircle },
  ];

  return (
    <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          <div className="flex items-center cursor-pointer" onClick={() => setActiveTab('home')}>
            <div className="flex-shrink-0 flex items-center gap-2">
              <div className="bg-emerald-500 p-2 rounded-lg">
                 <Hammer className="h-6 w-6 text-white" />
              </div>
              <span className="text-xl font-bold text-slate-800 tracking-tight">KnowApp</span>
            </div>
          </div>

          <div className="hidden sm:ml-6 sm:flex sm:space-x-8">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => setActiveTab(item.id)}
                className={`${
                  activeTab === item.id
                    ? 'border-emerald-500 text-slate-900'
                    : 'border-transparent text-slate-500 hover:border-slate-300 hover:text-slate-700'
                } inline-flex items-center px-1 pt-1 border-b-2 text-sm font-medium h-full transition-colors`}
              >
                <item.icon className="w-4 h-4 mr-2" />
                {item.label}
              </button>
            ))}
          </div>

          <div className="-mr-2 flex items-center sm:hidden">
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="inline-flex items-center justify-center p-2 rounded-md text-slate-400 hover:text-slate-500 hover:bg-slate-100 focus:outline-none focus:ring-2 focus:ring-inset focus:ring-emerald-500"
            >
              <span className="sr-only">Open main menu</span>
              {isMobileMenuOpen ? (
                <X className="block h-6 w-6" aria-hidden="true" />
              ) : (
                <Menu className="block h-6 w-6" aria-hidden="true" />
              )}
            </button>
          </div>
        </div>
      </div>

      {isMobileMenuOpen && (
        <div className="sm:hidden bg-white border-b border-slate-200">
          <div className="pt-2 pb-3 space-y-1">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id);
                  setIsMobileMenuOpen(false);
                }}
                className={`${
                  activeTab === item.id
                    ? 'bg-emerald-50 border-emerald-500 text-emerald-700'
                    : 'border-transparent text-slate-500 hover:bg-slate-50 hover:border-slate-300 hover:text-slate-700'
                } block pl-3 pr-4 py-2 border-l-4 text-base font-medium w-full text-left flex items-center`}
              >
                 <item.icon className="w-5 h-5 mr-3" />
                {item.label}
              </button>
            ))}
          </div>
        </div>
      )}
    </nav>
  );
};

import React from 'react';
import { Clock, MapPin, DollarSign, Gift, User } from 'lucide-react';
import { JobPost, BudgetType } from '../types';
import { CATEGORY_COLORS } from '../constants';

interface JobCardProps {
  job: JobPost;
}

export const JobCard: React.FC<JobCardProps> = ({ job }) => {
  const getBudgetDisplay = () => {
    switch (job.budgetType) {
      case BudgetType.FIXED:
        return <span className="flex items-center text-emerald-700 font-semibold"><DollarSign className="w-4 h-4 mr-1" />${job.budgetAmount} (Fixed)</span>;
      case BudgetType.HOURLY:
        return <span className="flex items-center text-emerald-700 font-semibold"><DollarSign className="w-4 h-4 mr-1" />${job.budgetAmount}/hr</span>;
      case BudgetType.BARTER:
        return <span className="flex items-center text-amber-700 font-semibold"><Gift className="w-4 h-4 mr-1" />Trade: {job.barterDescription}</span>;
      case BudgetType.VOLUNTEER:
        return <span className="flex items-center text-purple-700 font-semibold"><HeartHandshakeIcon className="w-4 h-4 mr-1" />Volunteer</span>;
      default:
        return null;
    }
  };

  // Helper component for icon
  const HeartHandshakeIcon = ({ className }: { className?: string }) => (
    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}><path d="M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.5 0 0 0 16.5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.5 0 0 0 2 8.5c0 2.3 1.5 4.05 3 5.5l7 7Z"/></svg>
  );

  return (
    <div className="bg-white rounded-lg shadow-sm border border-slate-200 hover:shadow-md transition-shadow p-6 mb-4">
      <div className="flex justify-between items-start mb-2">
        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${CATEGORY_COLORS[job.category]}`}>
          {job.category}
        </span>
        <span className="text-xs text-slate-500 flex items-center">
          <Clock className="w-3 h-3 mr-1" />
          {new Date(job.postedAt).toLocaleDateString()}
        </span>
      </div>

      <h3 className="text-lg font-bold text-slate-900 mb-2">{job.title}</h3>
      <p className="text-slate-600 text-sm mb-4 line-clamp-3">{job.description}</p>

      <div className="flex flex-col sm:flex-row sm:items-center justify-between text-sm text-slate-500 border-t border-slate-100 pt-4 gap-4">
        <div className="flex items-center gap-4">
            <span className="flex items-center">
            <User className="w-4 h-4 mr-1 text-slate-400" />
            {job.authorName}
            </span>
            <span className="flex items-center">
            <MapPin className="w-4 h-4 mr-1 text-slate-400" />
            {job.location}
            </span>
        </div>
        <div className="bg-slate-50 px-3 py-1 rounded-md border border-slate-100">
            {getBudgetDisplay()}
        </div>
      </div>

      <div className="mt-4 flex gap-2">
        <button className="flex-1 bg-white border border-slate-300 text-slate-700 font-medium py-2 rounded-md hover:bg-slate-50 transition-colors">
            Details
        </button>
        <button className="flex-1 bg-emerald-600 text-white font-medium py-2 rounded-md hover:bg-emerald-700 transition-colors">
            Contact
        </button>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Sparkles, AlertCircle } from 'lucide-react';
import { getProjectAdvice } from '../services/gemini';
import { ChatMessage } from '../types';

export const AIAdvisor: React.FC = () => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
      role: 'model', 
      text: "Hi! I'm the KnowApp Advisor. Describe your home project or problem, and I'll help you figure out what you need and how to ask for help on a budget." 
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    const advice = await getProjectAdvice(userMessage);

    setMessages(prev => [...prev, { role: 'model', text: advice }]);
    setIsLoading(false);
  };

  return (
    <div className="h-[calc(100vh-4rem)] flex flex-col bg-slate-50">
      {/* Header */}
      <div className="bg-white p-4 border-b border-slate-200 flex items-center justify-between shadow-sm">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-100 p-2 rounded-full">
            <Sparkles className="w-5 h-5 text-indigo-600" />
          </div>
          <div>
            <h2 className="text-lg font-bold text-slate-800">Project Advisor</h2>
            <p className="text-xs text-slate-500">Powered by Gemini AI</p>
          </div>
        </div>
      </div>

      {/* Warning Banner */}
      {!process.env.API_KEY && (
        <div className="bg-amber-50 border-b border-amber-200 p-2 text-xs text-amber-800 flex items-center justify-center">
            <AlertCircle className="w-3 h-3 mr-1"/>
            Demo Mode: AI responses are simulated because no API Key was provided.
        </div>
      )}

      {/* Chat Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg, idx) => (
          <div
            key={idx}
            className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`flex max-w-[85%] sm:max-w-[75%] gap-2 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${
                msg.role === 'user' ? 'bg-emerald-100' : 'bg-indigo-100'
              }`}>
                {msg.role === 'user' ? <User className="w-5 h-5 text-emerald-700" /> : <Bot className="w-5 h-5 text-indigo-700" />}
              </div>

              <div className={`p-3 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap ${
                msg.role === 'user' 
                  ? 'bg-emerald-600 text-white rounded-tr-none' 
                  : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none shadow-sm'
              }`}>
                {msg.text}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
           <div className="flex w-full justify-start">
            <div className="flex max-w-[80%] gap-2">
                <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center flex-shrink-0">
                    <Bot className="w-5 h-5 text-indigo-700" />
                </div>
                <div className="bg-white border border-slate-200 p-4 rounded-2xl rounded-tl-none shadow-sm">
                    <div className="flex items-center gap-2 text-slate-500 text-xs">
                        <Loader2 className="w-4 h-4 animate-spin" />
                        Analyzing project details...
                    </div>
                </div>
            </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="bg-white p-4 border-t border-slate-200">
        <form onSubmit={handleSubmit} className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="E.g., My kitchen sink is dripping..."
            className="flex-1 border border-slate-300 rounded-full px-4 py-2 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent text-sm"
          />
          <button
            type="submit"
            disabled={isLoading || !input.trim()}
            className="bg-emerald-600 text-white p-2 rounded-full hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center justify-center w-10 h-10"
          >
            <Send className="w-5 h-5" />
          </button>
        </form>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { JobCategory, BudgetType } from '../types';
import { AlertCircle, CheckCircle2 } from 'lucide-react';

export const PostJobForm: React.FC = () => {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: JobCategory.OTHER,
    budgetType: BudgetType.FIXED,
    budgetAmount: '',
    barterDescription: '',
    location: '',
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Simulate API call
    setTimeout(() => {
        setIsSubmitting(false);
        setIsSuccess(true);
        // Reset form after 2 seconds
        setTimeout(() => {
            setIsSuccess(false);
            setFormData({
                title: '',
                description: '',
                category: JobCategory.OTHER,
                budgetType: BudgetType.FIXED,
                budgetAmount: '',
                barterDescription: '',
                location: '',
            })
        }, 2000);
    }, 1500);
  };

  if (isSuccess) {
      return (
          <div className="flex flex-col items-center justify-center h-96 text-center animate-fade-in">
              <div className="bg-emerald-100 p-4 rounded-full mb-4">
                  <CheckCircle2 className="w-12 h-12 text-emerald-600" />
              </div>
              <h2 className="text-2xl font-bold text-slate-800">Job Posted Successfully!</h2>
              <p className="text-slate-500 mt-2">Your neighbors will see it soon.</p>
          </div>
      )
  }

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="px-6 py-4 border-b border-slate-200 bg-emerald-50/50">
        <h2 className="text-xl font-bold text-slate-800">Post a New Job</h2>
        <p className="text-sm text-slate-500">Describe what you need help with. Be honest about your budget.</p>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6">
        <div>
          <label htmlFor="title" className="block text-sm font-medium text-slate-700">Project Title</label>
          <input
            type="text"
            id="title"
            name="title"
            required
            value={formData.title}
            onChange={handleChange}
            placeholder="e.g., Fix leaking faucet"
            className="mt-1 block w-full border-slate-300 rounded-md shadow-sm focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm border p-2"
          />
        </div>

        <div>
          <label htmlFor="category" className="block text-sm font-medium text-slate-700">Category</label>
          <select
            id="category"
            name="category"
            value={formData.category}
            onChange={handleChange}
            className="mt-1 block w-full border-slate-300 rounded-md shadow-sm focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm border p-2 bg-white"
          >
            {Object.values(JobCategory).map((cat) => (
              <option key={cat} value={cat}>{cat}</option>
            ))}
          </select>
        </div>

        <div>
          <label htmlFor="description" className="block text-sm font-medium text-slate-700">Description</label>
          <textarea
            id="description"
            name="description"
            rows={4}
            required
            value={formData.description}
            onChange={handleChange}
            placeholder="Describe the issue. What tools do you have? What needs to be done?"
            className="mt-1 block w-full border-slate-300 rounded-md shadow-sm focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm border p-2"
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
                <label htmlFor="budgetType" className="block text-sm font-medium text-slate-700">Budget Type</label>
                <select
                    id="budgetType"
                    name="budgetType"
                    value={formData.budgetType}
                    onChange={handleChange}
                    className="mt-1 block w-full border-slate-300 rounded-md shadow-sm focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm border p-2 bg-white"
                >
                    {Object.values(BudgetType).map((type) => (
                    <option key={type} value={type}>{type}</option>
                    ))}
                </select>
            </div>

            {formData.budgetType === BudgetType.BARTER ? (
                <div>
                    <label htmlFor="barterDescription" className="block text-sm font-medium text-slate-700">What can you offer?</label>
                    <input
                        type="text"
                        id="barterDescription"
                        name="barterDescription"
                        required
                        value={formData.barterDescription}
                        onChange={handleChange}
                        placeholder="e.g., Home cooked meal, guitar lessons"
                        className="mt-1 block w-full border-slate-300 rounded-md shadow-sm focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm border p-2"
                    />
                </div>
            ) : formData.budgetType !== BudgetType.VOLUNTEER ? (
                <div>
                    <label htmlFor="budgetAmount" className="block text-sm font-medium text-slate-700">Amount ($)</label>
                    <input
                        type="number"
                        id="budgetAmount"
                        name="budgetAmount"
                        required
                        min="0"
                        value={formData.budgetAmount}
                        onChange={handleChange}
                        placeholder="0.00"
                        className="mt-1 block w-full border-slate-300 rounded-md shadow-sm focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm border p-2"
                    />
                </div>
            ) : (
                <div className="flex items-end pb-2">
                    <p className="text-xs text-slate-500 italic">Requesting volunteer help means no payment is exchanged.</p>
                </div>
            )}
        </div>

        <div>
          <label htmlFor="location" className="block text-sm font-medium text-slate-700">Location (City/Neighborhood)</label>
          <input
            type="text"
            id="location"
            name="location"
            required
            value={formData.location}
            onChange={handleChange}
            placeholder="e.g., North Hills"
            className="mt-1 block w-full border-slate-300 rounded-md shadow-sm focus:ring-emerald-500 focus:border-emerald-500 sm:text-sm border p-2"
          />
        </div>

        <div className="pt-4">
            <div className="rounded-md bg-blue-50 p-4 mb-4">
                <div className="flex">
                    <div className="flex-shrink-0">
                        <AlertCircle className="h-5 w-5 text-blue-400" aria-hidden="true" />
                    </div>
                    <div className="ml-3">
                        <h3 className="text-sm font-medium text-blue-800">Safety Tip</h3>
                        <div className="mt-2 text-sm text-blue-700">
                            <p>Never share personal financial information upfront. Meet neighbors in a safe manner.</p>
                        </div>
                    </div>
                </div>
            </div>

            <button
                type="submit"
                disabled={isSubmitting}
                className="w-full flex justify-center py-3 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-emerald-600 hover:bg-emerald-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 disabled:opacity-50 transition-colors"
            >
                {isSubmitting ? 'Posting...' : 'Post Job'}
            </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { JobPost, JobCategory } from '../types';
import { JobCard } from './JobCard';
import { MOCK_JOBS } from '../constants';
import { Search, Filter } from 'lucide-react';

export const JobBoard: React.FC = () => {
  const [filterCategory, setFilterCategory] = useState<string>('All');
  const [searchTerm, setSearchTerm] = useState('');

  const filteredJobs = MOCK_JOBS.filter(job => {
    const matchesCategory = filterCategory === 'All' || job.category === filterCategory;
    const matchesSearch = job.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          job.description.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-900">Available Jobs</h2>
            <p className="text-slate-500 mt-1">Find opportunities to help your neighbors.</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative rounded-md shadow-sm">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <Search className="h-4 w-4 text-slate-400" aria-hidden="true" />
                </div>
                <input
                    type="text"
                    className="focus:ring-emerald-500 focus:border-emerald-500 block w-full pl-10 sm:text-sm border-slate-300 rounded-md border p-2"
                    placeholder="Search jobs..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>

            <div className="relative rounded-md shadow-sm">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <Filter className="h-4 w-4 text-slate-400" aria-hidden="true" />
                </div>
                <select
                    value={filterCategory}
                    onChange={(e) => setFilterCategory(e.target.value)}
                    className="focus:ring-emerald-500 focus:border-emerald-500 block w-full pl-10 sm:text-sm border-slate-300 rounded-md border p-2 bg-white"
                >
                    <option value="All">All Categories</option>
