                                    <div className="bg-slate-50 rounded-md p-3 border border-slate-100 mt-4 flex flex-wrap gap-y-2 gap-x-6">
                                        <div className="flex items-center gap-2">
                                            <div className="flex items-center text-slate-600 text-xs font-medium">
                                                <Clock className="w-3.5 h-3.5 mr-1 text-slate-400" />
                                                Punctuality
                                            </div>
                                            {renderStars(review.metrics.punctuality, "w-3 h-3")}
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <div className="flex items-center text-slate-600 text-xs font-medium">
                                                <UserCheck className="w-3.5 h-3.5 mr-1 text-slate-400" />
                                                Professionalism
                                            </div>
                                            {renderStars(review.metrics.professionalism, "w-3 h-3")}
                                        </div>
                                        {review.metrics.broughtTools && (
                                            <div className="flex items-center gap-1.5 text-xs font-medium text-emerald-700 bg-emerald-100 px-2 py-0.5 rounded-full border border-emerald-200">
                                                <Wrench className="w-3 h-3" />
                                                Brought Own Tools
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                     ))
                 ) : (
                    <div className="text-center py-12 bg-white rounded-lg border border-dashed border-slate-300">
                        <MessageSquareQuote className="w-12 h-12 text-slate-300 mx-auto mb-3" />
                        <h3 className="text-lg font-medium text-slate-900">No reviews yet</h3>
                        <p className="text-slate-500 text-sm mt-1">Complete jobs to build your reference sheet!</p>
                    </div>
                 )}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MapPin, Calendar, Star, Briefcase, Heart, Plus, X, MessageSquareQuote, Clock, UserCheck, Wrench } from 'lucide-react';
import { MOCK_USER, MOCK_JOBS } from '../constants';
import { JobCard } from './JobCard';
import { JobPost } from '../types';

interface UserProfileProps {
    onContact?: (job: JobPost) => void;
}

export const UserProfile: React.FC<UserProfileProps> = ({ onContact }) => {
  const [activeTab, setActiveTab] = useState<'posted' | 'saved' | 'reviews'>('posted');
  const [skills, setSkills] = useState<string[]>(MOCK_USER.skills || []);
  const [newSkill, setNewSkill] = useState('');

  // Simulate filtering jobs for the current user
  const myJobs = MOCK_JOBS.slice(0, 2); 
  const savedJobs = MOCK_JOBS.slice(2, 4); 

  const handleAddSkill = (e: React.FormEvent) => {
    e.preventDefault();
    if (newSkill.trim() && !skills.includes(newSkill.trim())) {
      setSkills([...skills, newSkill.trim()]);
      setNewSkill('');
    }
  };

  const removeSkill = (skillToRemove: string) => {
    setSkills(skills.filter(s => s !== skillToRemove));
  };

  const renderStars = (rating: number, size: string = "w-4 h-4") => {
    return (
      <div className="flex">
        {[...Array(5)].map((_, i) => (
          <Star 
            key={i} 
            className={`${size} ${i < rating ? 'text-yellow-400 fill-yellow-400' : 'text-slate-300'}`} 
          />
        ))}
      </div>
    );
  };

  return (
    <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Profile Header */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mb-6">
        <div className="h-32 bg-gradient-to-r from-emerald-500 to-teal-600"></div>
        <div className="px-6 pb-6">
          <div className="relative flex items-end -mt-12 mb-4">
            <div className="p-1.5 bg-white rounded-full">
                <img 
                    src={MOCK_USER.avatarUrl} 
                    alt={MOCK_USER.name} 
                    className="w-24 h-24 rounded-full bg-slate-100 object-cover border border-slate-100"
                />
            </div>
            <div className="ml-4 mb-1">
                <h1 className="text-2xl font-bold text-slate-900">{MOCK_USER.name}</h1>
                <div className="flex items-center text-slate-500 text-sm">
                    <MapPin className="w-4 h-4 mr-1" />
                    {MOCK_USER.location}
                </div>
            </div>
          </div>

          <div className="flex flex-col md:flex-row gap-6 md:items-start justify-between">
              <div className="max-w-2xl w-full">
                  <p className="text-slate-600 mb-4">{MOCK_USER.bio}</p>
                  <div className="flex flex-wrap gap-4 text-sm text-slate-500 mb-5">
                      <div className="flex items-center">
                          <Calendar className="w-4 h-4 mr-1.5 text-slate-400" />
                          Joined {MOCK_USER.memberSince}
                      </div>
                      <div className="flex items-center">
                           <Star className="w-4 h-4 mr-1.5 text-yellow-400 fill-yellow-400" />
                           {MOCK_USER.stats.rating} Rating ({MOCK_USER.stats.jobsCompleted} jobs done)
                      </div>
                  </div>

                  {/* Skills Section */}
                  <div className="mb-2">
                    <h3 className="text-sm font-semibold text-slate-900 mb-2">Skills & Expertise</h3>
                    <div className="flex flex-wrap gap-2 items-center">
                        {skills.map(skill => (
                            <span key={skill} className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-emerald-50 text-emerald-700 border border-emerald-100 group">
                                {skill}
                                <button 
                                  onClick={() => removeSkill(skill)} 
                                  className="ml-1.5 text-emerald-400 hover:text-emerald-600 focus:outline-none"
                                  title="Remove skill"
                                >
                                    <X className="w-3 h-3" />
                                </button>
                            </span>
                        ))}
                        <form onSubmit={handleAddSkill} className="inline-flex items-center">
                            <input 
                                type="text"
                                value={newSkill}
                                onChange={(e) => setNewSkill(e.target.value)}
                                placeholder="Add skill..."
                                className="w-24 text-xs border border-slate-300 rounded-l-full px-2 py-0.5 focus:outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 placeholder:text-slate-400"
                            />
                            <button 
                                type="submit" 
                                disabled={!newSkill.trim()}
                                className="bg-slate-100 border border-l-0 border-slate-300 rounded-r-full px-2 py-0.5 hover:bg-slate-200 disabled:opacity-50 transition-colors"
                                title="Add skill"
                            >
                                <Plus className="w-3 h-3 text-slate-600" />
                            </button>
                        </form>
                    </div>
                  </div>
              </div>
              <div className="flex gap-3 flex-shrink-0">
                  <button className="px-4 py-2 bg-slate-100 text-slate-700 rounded-md font-medium hover:bg-slate-200 transition-colors h-fit">
                      Edit Profile
                  </button>
              </div>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="border-b border-slate-200 mb-6">
        <nav className="-mb-px flex space-x-8 overflow-x-auto">
          <button
            onClick={() => setActiveTab('posted')}
            className={`${
              activeTab === 'posted'
                ? 'border-emerald-500 text-emerald-600'
                : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
            } whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm flex items-center`}
          >
            <Briefcase className="w-4 h-4 mr-2" />
            Posted Jobs ({myJobs.length})
          </button>
          <button
            onClick={() => setActiveTab('saved')}
            className={`${
              activeTab === 'saved'
                ? 'border-emerald-500 text-emerald-600'
                : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
            } whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm flex items-center`}
          >
            <Heart className="w-4 h-4 mr-2" />
            Saved / Applied ({savedJobs.length})
          </button>
          <button
            onClick={() => setActiveTab('reviews')}
            className={`${
              activeTab === 'reviews'
                ? 'border-emerald-500 text-emerald-600'
                : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
            } whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm flex items-center`}
          >
            <MessageSquareQuote className="w-4 h-4 mr-2" />
            Reviews & References ({MOCK_USER.reviews ? MOCK_USER.reviews.length : 0})
          </button>
        </nav>
      </div>

      {/* Content */}
      <div className="min-h-[300px]">
        {activeTab === 'posted' && (
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {myJobs.length > 0 ? (
                    myJobs.map(job => <JobCard key={job.id} job={job} onContact={onContact} />)
                ) : (
                    <div className="col-span-full text-center py-8 text-slate-500">
                        You haven't posted any jobs yet.
                    </div>
                )}
             </div>
        )}

        {activeTab === 'saved' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {savedJobs.length > 0 ? (
                    savedJobs.map(job => <JobCard key={job.id} job={job} onContact={onContact} />)
                ) : (
                    <div className="col-span-full text-center py-8 text-slate-500">
                        No saved jobs or applications.
                    </div>
                )}
            </div>
        )}

        {activeTab === 'reviews' && (
            <div className="space-y-6">
                 {MOCK_USER.reviews && MOCK_USER.reviews.length > 0 ? (
                     MOCK_USER.reviews.map(review => (
                        <div key={review.id} className="bg-white rounded-lg shadow-sm border border-slate-200 p-6 flex flex-col md:flex-row gap-4 md:gap-6">
                            <div className="flex-shrink-0 flex md:flex-col items-center gap-2 md:w-24">
                                <img 
                                    src={review.reviewerAvatar} 
                                    alt={review.reviewerName} 
                                    className="w-12 h-12 rounded-full bg-slate-100 object-cover border border-slate-100" 
                                />
                                <div className="text-center hidden md:block">
                                    <div className="text-xs font-medium text-slate-900">{review.reviewerName}</div>
                                </div>
                            </div>

                            <div className="flex-1">
                                <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start mb-2">
                                    <div>
                                        <div className="flex items-center gap-2 mb-1">
                                            <h3 className="text-lg font-bold text-slate-900">{review.jobTitle}</h3>
                                            <span className="md:hidden text-xs text-slate-500">by {review.reviewerName}</span>
                                        </div>
                                        {renderStars(review.rating)}
                                    </div>
                                    <div className="text-xs text-slate-400 mt-2 sm:mt-0 whitespace-nowrap">
                                        {new Date(review.date).toLocaleDateString()}
                                    </div>
                                </div>
                                <div className="relative mt-3 mb-4">
                                    <span className="absolute top-0 left-0 -mt-2 -ml-2 text-4xl text-slate-200 opacity-50 font-serif">"</span>
                                    <p className="text-slate-600 text-sm leading-relaxed italic relative z-10 px-2">
                                        {review.comment}
                                    </p>
                                </div>

                                {review.metrics && (
                                    <div className="bg-slate-50 rounded-md p-3 border border-slate-100 mt-4 flex flex-wrap gap-y-2 gap-x-6">
                                        <div className="flex items-center gap-2">
                                            <div className="flex items-center text-slate-600 text-xs font-medium">
                                                <Clock className="w-3.5 h-3.5 mr-1 text-slate-400" />
                                                Punctuality
                                            </div>
                                            {renderStars(review.metrics.punctuality, "w-3 h-3")}
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <div className="flex items-center text-slate-600 text-xs font-medium">
                                                <UserCheck className="w-3.5 h-3.5 mr-1 text-slate-400" />
                                                Professionalism
                                            </div>
                                            {renderStars(review.metrics.professionalism, "w-3 h-3")}
                                        </div>
                                        {review.metrics.broughtTools && (
                                            <div className="flex items-center gap-1.5 text-xs font-medium text-emerald-700 bg-emerald-100 px-2 py-0.5 rounded-full border border-emerald-200">
                                                <Wrench className="w-3 h-3" />
                                                Brought Own Tools
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                     ))
                 ) : (
                    <div className="text-center py-12 bg-white rounded-lg border border-dashed border-slate-300">
                        <MessageSquareQuote className="w-12 h-12 text-slate-300 mx-auto mb-3" />
                        <h3 className="text-lg font-medium text-slate-900">No reviews yet</h3>
                        <p className="text-slate-500 text-sm mt-1">Complete jobs to build your reference sheet!</p>
                    </div>
                 )}
            </div>
        )}
      </div>
    </div>
  );
};
